    14→// GitLabProvider implements GitProvider for GitLab instances
    15→type GitLabProvider struct {
    16→	baseURL string
    17→	token   string
    18→	client  *http.Client
    19→}
    20→
    21→// NewGitLabProvider creates a new GitLab provider instance
    22→func NewGitLabProvider() *GitLabProvider {
    23→	baseURL := os.Getenv("GITLAB_URL")
    24→	if baseURL == "" {
    25→		baseURL = "https://gitlab.com"
    26→	}
    27→
    28→	token := os.Getenv("GITLAB_TOKEN")
    29→
    30→	return &GitLabProvider{
    31→		baseURL: baseURL,
    32→		token:   token,
    33→		client:  &http.Client{},
    34→	}
    35→}
    36→
    37→// ValidateConfiguration validates that required configuration is present
    38→func (g *GitLabProvider) ValidateConfiguration() error {
    39→	if g.token == "" {
    40→		return fmt.Errorf("GITLAB_TOKEN environment variable is required")
    41→	}
    42→	return nil
    43→}
