    82→// findExistingMR searches for an existing MR with the same source branch
    83→func (g *GitLabProvider) findExistingMR(ctx context.Context, project, sourceBranch string) (*gitLabMRResponse, error) {
    84→	// URL encode the project path
    85→	encodedProject := url.PathEscape(project)
    86→	apiURL := fmt.Sprintf("%s/api/v4/projects/%s/merge_requests?source_branch=%s&state=opened",
    87→		g.baseURL, encodedProject, url.QueryEscape(sourceBranch))
    88→
    89→	req, err := http.NewRequestWithContext(ctx, "GET", apiURL, nil)
    90→	if err != nil {
    91→		return nil, fmt.Errorf("failed to create request: %w", err)
    92→	}
    93→
    94→	req.Header.Set("Authorization", "Bearer "+g.token)
    95→	req.Header.Set("Content-Type", "application/json")
    96→
    97→	resp, err := g.client.Do(req)
    98→	if err != nil {
    99→		return nil, fmt.Errorf("failed to make API request: %w", err)
   100→	}
   101→	defer resp.Body.Close()
   102→
   103→	if resp.StatusCode != http.StatusOK {
   104→		return nil, fmt.Errorf("GitLab API error: status %d", resp.StatusCode)
   105→	}
   106→
   107→	var mrs []gitLabMRResponse
   108→	if err := json.NewDecoder(resp.Body).Decode(&mrs); err != nil {
   109→		return nil, fmt.Errorf("failed to decode response: %w", err)
   110→	}
   111→
   112→	if len(mrs) > 0 {
   113→		return &mrs[0], nil
   114→	}
   115→
   116→	return nil, nil // No existing MR found
   117→}
