   169→// updateMR updates an existing GitLab merge request
   170→func (g *GitLabProvider) updateMR(ctx context.Context, project string, mrIID int, config MRConfig) (*MRResult, error) {
   171→	// Prepare target branch (strip refs/heads/ prefix if present)
   172→	targetBranch := strings.TrimPrefix(config.TargetBranch, "refs/heads/")
   173→
   174→	mrRequest := gitLabMRRequest{
   175→		Title:        config.Title,
   176→		Description:  config.Description,
   177→		TargetBranch: targetBranch,
   178→		Labels:       strings.Join(config.Labels, ","),
   179→	}
   180→
   181→	body, err := json.Marshal(mrRequest)
   182→	if err != nil {
   183→		return nil, fmt.Errorf("failed to marshal request: %w", err)
   184→	}
   185→
   186→	encodedProject := url.PathEscape(project)
   187→	apiURL := fmt.Sprintf("%s/api/v4/projects/%s/merge_requests/%d", g.baseURL, encodedProject, mrIID)
   188→
   189→	req, err := http.NewRequestWithContext(ctx, "PUT", apiURL, bytes.NewBuffer(body))
   190→	if err != nil {
   191→		return nil, fmt.Errorf("failed to create request: %w", err)
   192→	}
   193→
   194→	req.Header.Set("Authorization", "Bearer "+g.token)
   195→	req.Header.Set("Content-Type", "application/json")
   196→
   197→	resp, err := g.client.Do(req)
   198→	if err != nil {
   199→		return nil, fmt.Errorf("failed to make API request: %w", err)
   200→	}
   201→	defer resp.Body.Close()
   202→
   203→	if resp.StatusCode != http.StatusOK {
   204→		return nil, fmt.Errorf("GitLab API error: status %d", resp.StatusCode)
   205→	}
   206→
   207→	var mrResponse gitLabMRResponse
   208→	if err := json.NewDecoder(resp.Body).Decode(&mrResponse); err != nil {
   209→		return nil, fmt.Errorf("failed to decode response: %w", err)
   210→	}
   211→
   212→	return &MRResult{
   213→		MRURL: mrResponse.WebURL,
   214→		MRID:  mrResponse.IID,
   215→	}, nil
   216→}
